state:
p : Char → Bool
s : String
⊢ s.dropWhile p = { data := List.dropWhile p s.data }

p : Char → Bool
s : String
⊢ (s.toSubstring.dropWhile p).toString = { data := List.dropWhile p s.data }

p : Char → Bool
s : String
⊢ ({ str := s, startPos := 0, stopPos := s.endPos }.dropWhile p).toString = { data := List.dropWhile p s.data }
